var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"좋아. 그럼 첫 번째 숙제는......","JPN":"よし。じゃあ、一つ目は……","ENG":"Alright, then your first task is...","TWN":"很好，那麼第一個功課是......"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"꿀꺽......","JPN":"ごくりっ……","ENG":"*Gulp*","TWN":"咕嗒......（吞口水聲音）"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"두구두구두구두구~","JPN":"ドキドキ……ワクワク……","ENG":"Drumroll please!","TWN":"咚咚咚咚咚咚~"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"에잇! 조용히 해, 츠바이! 너 때문에 더 긴장되잖아!","JPN":"ねえ、静かにしてよ！　なんか緊張してくるじゃない！","ENG":"Eek! Be quiet, Zwei! You're making me nervous!","TWN":"唉！安靜點，茨粨！ 因爲你更緊張了！"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"에헤헤~ 기대되는 걸 어떡해~","JPN":"だって～楽しみなんだもん～。","ENG":"Hee hee, but I'm so excited!","TWN":"啊嘿嘿~ 好期待啊，怎麼辦~"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"첫 번째 숙제는 보물찾기다.","JPN":"一つ目の宿題は、お宝探しだ。","ENG":"Your first task is a treasure hunt.","TWN":"第一個功課就是尋寶。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"보물......","JPN":"お宝……","ENG":"A treasure...","TWN":"尋......"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"찾기?","JPN":"探し……？","ENG":"Hunt?","TWN":"寶？"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 이 사무실 어딘가에 숨겨져 있는 보물을 찾는 거란다.","JPN":"ああ。この事務所のどこかに隠してある宝物を探すんだ。","ENG":"Yes. I want you to find the treasure that's hidden somewhere in this office.","TWN":"對，就是尋找隱藏在這辦公室的某個地方的寶物。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이렇게 생겼고 반짝거리는 황금색 트로피지.","JPN":"見た目はこんな感じ。黄金に輝くトロフィーだ。","ENG":"It's a shiny gold trophy shaped like this.","TWN":"是長這樣閃閃發光的金黃色獎盃。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"우와, 반짝거려?","JPN":"すごーい、輝くの？","ENG":"Whoa, is it shiny?","TWN":"哇啊，閃閃發光啊？"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"그런데 어떻게 잃어 버린 거야? 반짝거리면 찾기 쉽잖아?","JPN":"でも、どうして失くしたの？　輝くものならすぐ見つかるでしょ？","ENG":"Then, how did you lose it? If it's shiny, it should be easy to find.","TWN":"但是怎麼弄丟的呢？ 閃閃發光就容易找到吧？"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"난 왜 잃어 버렸는지 알아. 집에 도둑이 들었던 게 분명해.","JPN":"わたしにはわかるわ。きっとドロボウが入ったんだよ。","ENG":"I know why he lost it. A burglar must have stolen it.","TWN":"我知道爲什麼弄丟了，家裡一定有小偷。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 다행히 도둑은 아니었단다.","JPN":"ははっ、幸いドロボウではなかったよ。","ENG":"Hah hah. Fortunately, there was no burglar.","TWN":"哈哈，幸虧不是小偷啊。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"며칠 전에 같이 일하는 언니가 나한테 보물 찾기를 하자면서 숨겨 놓았거든.","JPN":"数日前に、お兄ちゃんの仕事仲間のお姉ちゃんがお宝探しをしててね、隠したんだ。","ENG":"One of my coworkers hid it a few days ago because she wanted to have a treasure hunt with me.","TWN":"幾天前一起工作的姐姐跟我說要找寶物，所以藏起來了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런데 너무 꼭꼭 숨겨 놓는 바람에 혼자서는 찾을 수가 없단다.","JPN":"だけどね、誰にもわからないところに隠しちゃって、お兄ちゃん一人では見つけられなかったんだよ。","ENG":"But she hid it so well, I haven't been able to find it.","TWN":"但是隱藏得太深，所以一個人沒辦法找到。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 트로피가 없으면 직원들이 아주 슬퍼할 텐데......","JPN":"そのトロフィーが見つからないと、みんなが悲しんじゃうんだ……","ENG":"My employees will be very sad if I don't find the trophy.","TWN":"如果沒有那個獎盃，員工們會很傷心的……"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"걱정 마, 오빠. 내가 금방 찾아다 줄게.","JPN":"お兄ちゃん、心配しないで。わたしが見つけてあげる。","ENG":"Don't worry, Brother. I'll find it for you in a jiffy.","TWN":"別擔心，哥哥。 我馬上就找給你。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"나도 찾는 건 자신 있어. 우리 중에 냄새를 제일 잘 맡거든.","JPN":"ぼくも探し物には自信あるよ！　ぼくたちの中で一番鼻が利くからね。","ENG":"I'll help, too. I have the keenest nose among all of us.","TWN":"我很有信心找東西，我們當中我是最能聞味道的。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"흥. 맛있는 냄새만 잘 맡으면서.","JPN":"食べ物の匂いにしか反応しなかったんじゃないの？","ENG":"Pffft, you can only smell food.","TWN":"哼，只會聞到好吃的。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 둘 다 자신감이 넘치는구나.","JPN":"ははっ、二人ともずいぶん自信があるようだね。","ENG":"Hah hah. Both of you are so confident.","TWN":"哈哈，兩個人都充滿自信。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러면 시작해 볼까?","JPN":"それじゃ始めるよ？","ENG":"Okay, then let's get started.","TWN":"那麼開始吧？"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"준비......","JPN":"よーい……","ENG":"Ready...","TWN":"預備......"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"시작!","JPN":"スタート！","ENG":"Go!","TWN":"開始！"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"오빠~ 이 커다란 도시락통은 뭐야?","JPN":"お兄ちゃ～ん、この大きなお弁当箱はなぁに？","ENG":"Brother, what's this big lunch box doing here?","TWN":"哥哥~ 這麼大的便當盒是什麼？"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흠, 소빈 양이 들고 다니는 물건이구나. 평소엔 그 안에 맛있는 게 가득 들어 있단다.","JPN":"それは、コハル君のだね。いつもはそこに美味しいものがいっぱい入ってるよ。","ENG":"Ah, that's Sobin's lunch box. It's usually filled with delicious food.","TWN":"嗯，是素蘋小姐攜帶的東西，平常那裡面有裝滿好吃的。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"와아~ 얼른 다시 찼으면 좋겠다~","JPN":"へえ～早くまたいっぱいになるといいな～。","ENG":"Ooo, I can't wait for it to be filled again!","TWN":"哇啊~ 快點重新裝滿就好了~"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"오빠, 내가 반짝거리는 유리 구슬을 찾았거든?","JPN":"お兄ちゃん、わたしキラキラのガラス玉を見つけたよ！","ENG":"Brother, I've found a shiny glass ball.","TWN":"哥哥，我找到閃亮亮的玻璃珠子了？"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"엄청 예쁘지? 트로피보다 이게 더 마음에 들지 않아?","JPN":"すごくきれいでしょう？　トロフィーよりこっちがよくない？","ENG":"So pretty, isn't it? Don't you like this better than the trophy?","TWN":"很漂亮吧？比起獎盃不覺得更滿意這個嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그건 클로에 양이 제일 아끼는 수정구슬이란다. 다른 사람이 가져가면 아주 슬퍼할 거야.","JPN":"それはクロエ君の大事な水晶玉だ。誰かに持っていかれたら悲しむと思うよ。","ENG":"That's the crystal ball that Chloe loves the most. She'll be very sad if she loses it.","TWN":"那是克洛伊小姐最珍惜的水晶珠子，如果別人拿走她會很傷心的。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"치이...... 그럼 됐어.","JPN":"うーん……わかったわ。","ENG":"Piff... Then, forget it.","TWN":"切...... 那就算了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"와아~ 이 방에는 신기한 게 엄청 많다~","JPN":"うわぁ～この部屋には不思議なものがいっぱいあるよ～！","ENG":"Whoa, there are lots of interesting things in this room!","TWN":"哇啊~ 在這個房間裡有很多神奇的東西~"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아, 거긴 비품 창고란다. 위험한 물건도 있으니까 조심하렴.","JPN":"あ、そこは備品倉庫だよ。危ないものも入ってるから気をつけるんだぞ。","ENG":"Oh, that's a supply storage closet. Please be careful. Some of the things in it are very dangerous.","TWN":"啊，這裡是常備品倉庫，裡面也有危險的東西要小心喔。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"앗! 기다려, 츠바이! 나도 거기 찾아 볼래!","JPN":"ちょっと待って、ツヴァイ！　わたしもそこ探す！","ENG":"Ah! Wait, Zwei! I want to check that place, too!","TWN":"咦！等等，茨粨！我也要找找那裡！"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"사무실이 또 난장판이 되게 생겼군. 요즘 들어 청소 맡길 일이 점점 늘어나는 것 같아.","JPN":"事務所がまた修羅場になりそうだな……最近掃除を頼む頻度が増えた気がする。","ENG":"My office is going to get messy again. I'm in need of cleaning services too often lately.","TWN":"看來辦公室又亂七八糟了。最近委託打掃的工作好像越來越多了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만......","JPN":"しかし……","ENG":"But...","TWN":"可是......"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"애들 노는 걸 보고 있으려니 옛날 생각도 나는데.","JPN":"遊んでいる子どもたちを見てると、昔のこと思い出すな。","ENG":"Watching these girls play, I can't help but think of the old days.","TWN":"看著孩子們在玩就想起以前了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_CHILD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 아이는...... 나이대에 안 맞게 너무 얌전해서 걱정이었지만.","JPN":"あの子は……歳に似合わず大人しすぎたけど。","ENG":"She was way too quiet for her age, though.","TWN":"那個孩子...... 不像同年齡的孩子太文靜了，所以很擔心。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_CHILD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음? 무슨 소리지?","JPN":"ん？　何の音だ……？","ENG":"Mm? What was that noise?","TWN":"嗯？什麼聲音？"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"크앙~ 나는 무서운 침식체다~ 크아앙~","JPN":"わーーっ、ぼくは怖～い侵食体だぞ～！　わーーーっ！","ENG":"Rawr! I'm a scary C.O.! Rawr!","TWN":"咳啊~ 我是可怕的侵蝕體~ 咳啊啊~"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"으아앙! 오빠아~! 무서워!","JPN":"いやあああ！　お兄ちゃ～ん、怖いよ～！","ENG":"Boohoo! Brother, I'm scared!","TWN":"嗚嗚嗚！哥哥啊~！我好怕啊！"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자, 자. 울지 말고 잘 보렴. 진짜 침식체가 아니라 네 동생이야.","JPN":"ほら、泣かないでちゃんと見てごらん？\\n侵食体じゃなくて、君の妹だよ。","ENG":"There, there. Stop crying and look. That's not a real C.O. It's your sister.","TWN":"來，來。不要哭，你看看，這不是侵蝕體，而是你妹妹。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"츠바이, 그 침식체 가면은 어디서 구한 거니?","JPN":"ツヴァイ、その侵食体マスクはどこで見つけたんだい？","ENG":"Zwei, where did you find that C.O. mask?","TWN":"茨粨，那個侵蝕體面具是從哪裡弄來的？"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"창고에서 찾았어. 살짝 놀래 주려고 했는데 아인은 진짜 겁이 많은가 봐.","JPN":"倉庫にあったよ！　ちょっとびっくりさせようと思ったけど、アインって本当に臆病だね。","ENG":"In that storage closet. I just wanted to mess with her. I didn't mean to scare her so much.","TWN":"在倉庫裡找到的，本來想稍微嚇唬一下的，看來艾茵真的很膽小。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"하, 하나도 겁 안 났거든? 그냥 무서운 척만 한 거거든?","JPN":"全然驚いてないもん！　付き合ってあげただけだもん！","ENG":"I-I wasn't scared at all! I only pretended I was!","TWN":"我、我一點都不害怕，我只是裝害怕而已。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"에이~ 말도 안 돼~","JPN":"嘘だ～。","ENG":"Piff, you're lying.","TWN":"唉~ 才不像~"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L39_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"아냐, 진짜야!","JPN":"本当だってば！","ENG":"No, I'm not!","TWN":"沒有啊，真的！"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L40_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"우리 중에는 내가 제일 어른인걸. 어른이 겁먹는 거 봤어?","JPN":"だってわたしたちの中で、アインが一番大人でしょ？　大人は怖がったりしないんだから。","ENG":"I'm the oldest among all of us. Have you seen any grownups scared?","TWN":"在我們之中我是最大的大人，看過大人害怕了嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오, 그러면 동생들이 무서워할 때는 네가 지켜 주겠구나.","JPN":"なるほど、それじゃ妹たちが怖がってるときは君が守ってあげるのかい？","ENG":"Oh, so you protect your sisters when they're scared, huh?","TWN":"喔，那麼妹妹們害怕的時候，你可以保護她們。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"다...... 당연하지! 침식체들이 덤비면 내가 다 혼내 줄 거야!","JPN":"も……もちろんよ！　侵食体なんて、わたしが痛い目にあわせてやるんだから！","ENG":"O-of course! I can beat any C.O.s that come at us!","TWN":"當...... 當然啊！侵蝕體一撲過來，我會教訓他的！ "},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"굉장한데. 사실 난 침식체가 무섭거든.","JPN":"すごいなぁ。私はまだ侵食体のことが怖いのに。","ENG":"That's amazing because I'm scared of C.O.s.","TWN":"真厲害！其實我很怕侵蝕體。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"응? 오빠는 어른 아니야?","JPN":"えっ、お兄ちゃん……大人じゃないの？","ENG":"Huh? But you're a grownup.","TWN":"嗯？哥哥不是大人嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어른들도 침식체는 무서워한단다. 그러니까 저 무서운 가면도 창고에 숨겨 뒀지.","JPN":"大人だって怖いものは怖いんだよ。だからそのマスクも倉庫の中に隠しておいたわけだ。","ENG":"Even grownups are scared of C.O.s. That's why we hid that scary-looking mask in the storage closet.","TWN":"大人也會害怕侵蝕體啊，所以把那個可怕的面具也藏在倉庫裡了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"흐흠. 안 되겠네. 침식체가 나타나면 내가 오빠도 같이 지켜 줄게.","JPN":"へえーわかった。侵食体が現れたら、わたしがお兄ちゃんのことも守ってあげる。","ENG":"Hmm... Okay, then I'll protect you, too, if C.O.s show up.","TWN":"嗯，不行了，如果侵蝕體出現我會保護哥哥的。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하. 말만 들어도 든든한걸.","JPN":"ははっ、それは頼もしいな。","ENG":"Hah hah. Just hearing that makes me feel safe.","TWN":"哈哈，光聽就覺得很踏實。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런데 어떻게 혼내 주려고? 침식체는 사람보다 힘도 세고 총알도 튕겨낼 만큼 단단한데?","JPN":"でも、どうやって痛い目にあわせてやるんだい？侵食体は人間より力も強いし、銃弾も弾くくらい堅いんだよ？","ENG":"By the way, how are you going to protect me? C.O.s are stronger than people, and even bullets can't hurt them.","TWN":"不過怎麼教訓呢？ 侵蝕體比人力氣大，結實得連子彈都能彈出來。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"엣헴. 그건 말이야......","JPN":"えっへん、それはね……","ENG":"Ahem! Let me explain...","TWN":"唉嘿，那個嘛......"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};